SELECT SUM(quantity * current_price) AS total_portfolio_value
FROM portfolio_composition
WHERE portfolio_id = 0;

SELECT AVG(market_cap) AS average_market_cap
FROM stocks
WHERE exchange = 'New York Stock Exchange';

SELECT SUM(market_cap) AS total_market_cap
FROM stocks
WHERE sector = 'Technology';

SELECT portfolio_name, total_value 
FROM portfolios 
WHERE total_value = (SELECT MAX(total_value) FROM portfolios);
